import{_ as t,o as a,c as r,a7 as i}from"./chunks/framework.C5fSpjcB.js";const f=JSON.parse('{"title":"Creations","description":"","frontmatter":{},"headers":[],"relativePath":"en/items/creations.md","filePath":"en/items/creations.md","lastUpdated":1775394001000}'),s={name:"en/items/creations.md"};function o(n,e,l,c,d,h){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="creations" tabindex="-1">Creations <a class="header-anchor" href="#creations" aria-label="Permalink to &quot;Creations&quot;">​</a></h1><p><strong>Creations</strong> are items crafted in the <a href="./../modes/smelting.html">Smelting Room</a>. They provide various utility effects and are a key part of progression in Morimens.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>In Morimens, &quot;Creations&quot; (造物) primarily refers to <strong>Artifacts</strong> obtained during roguelike exploration runs. These are temporary relics that provide powerful passive effects for the duration of a single run. They are distinct from permanent crafted items.</p><p>Artifacts are obtained by defeating <strong>elite enemies</strong> during exploration. After an elite battle, you choose 1 artifact from 3 options (typically 2 with drawbacks + 1 positive). Artifacts with drawbacks still provide beneficial effects but come with a negative side effect.</p><h2 id="artifact-tiers" tabindex="-1">Artifact Tiers <a class="header-anchor" href="#artifact-tiers" aria-label="Permalink to &quot;Artifact Tiers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tier</th><th>Cost (Shop)</th><th>Description</th></tr></thead><tbody><tr><td><strong>Silver</strong> (银色)</td><td>~50 Black Sigils</td><td>Moderate passive effects. Available for purchase in exploration shops</td></tr><tr><td><strong>Gold</strong> (金色)</td><td>~90 Black Sigils</td><td>Powerful passive effects. Available for purchase in exploration shops</td></tr><tr><td><strong>Cursed</strong> (诅咒)</td><td>Not sold</td><td>Strong effects paired with negative drawbacks. Only obtained from elite enemies and specific events</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Cursed artifacts cannot be purchased from shops. They only drop from elite enemy encounters and special exploration events. Weigh the drawback carefully before accepting one.</p></div><h2 id="how-to-obtain-artifacts" tabindex="-1">How to Obtain Artifacts <a class="header-anchor" href="#how-to-obtain-artifacts" aria-label="Permalink to &quot;How to Obtain Artifacts&quot;">​</a></h2><ol><li><strong>Elite Battles</strong> -- Defeat elite enemies during roguelike exploration to choose from 3 artifacts.</li><li><strong>Exploration Shops</strong> -- Spend Black Sigils (黑印) earned from combat to buy Silver or Gold artifacts.</li><li><strong>Special Events</strong> -- Some random events on the exploration map offer artifacts as rewards.</li></ol><h2 id="smelting-room" tabindex="-1">Smelting Room <a class="header-anchor" href="#smelting-room" aria-label="Permalink to &quot;Smelting Room&quot;">​</a></h2><p>The <strong>Smelting Room</strong> (冶炼室) is a separate facility for permanent item exchange and crafting. It is not the same as the temporary artifact system.</p><table tabindex="0"><thead><tr><th>Function</th><th>Description</th></tr></thead><tbody><tr><td>Equipment exchange</td><td>Trade in items for upgraded versions</td></tr><tr><td>Material conversion</td><td>Convert surplus materials into needed ones</td></tr><tr><td>Special crafting</td><td>Craft limited items as recipes become available</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>New Smelting Room recipes unlock as you progress through the main story or complete specific milestones. Check back regularly after clearing new chapters.</p></div><h2 id="alchemy-system" tabindex="-1">Alchemy System <a class="header-anchor" href="#alchemy-system" aria-label="Permalink to &quot;Alchemy System&quot;">​</a></h2><p>The <strong>Alchemy</strong> (炼金) system handles material synthesis:</p><ul><li><strong>3 low-tier materials = 1 higher-tier material</strong> (e.g., 3 Pale Notes = 1 Pale File)</li><li><strong>30 Mimetic Crystals = 1 advanced skill material</strong></li></ul><h2 id="related-systems" tabindex="-1">Related Systems <a class="header-anchor" href="#related-systems" aria-label="Permalink to &quot;Related Systems&quot;">​</a></h2><ul><li><strong>Inscriptions</strong> (刻印) -- Defeating normal enemies lets you inscribe bonus effects onto 3 cards (choose from random options). These are separate from artifacts.</li><li><strong>Level Recall</strong> (等级回溯) -- Resets an Awakener&#39;s levels, skills, and ascension. All consumed materials are fully refunded. Breakthrough materials return as 30 Mimetic Crystals each.</li></ul><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Items Overview</a></li><li><a href="./../modes/smelting.html">Smelting Room</a></li><li><a href="./materials.html">Materials</a></li></ul>',21)])])}const p=t(s,[["render",o]]);export{f as __pageData,p as default};
